# ==============================================================================
# This checks for phrases that are generic and therefore do not belong
# to a specific type.
#
# Specially formatted and masked entries are also possible.
#
# ------------------------------------------------------------------------------
# Language: German
# Weight:   6.0
# ==============================================================================

# Special
# ==============================================================================

# Just a number
/\d{6,}$/i
/^\d$/i

# Sample: (626498645)
/\(\d{6,15}\)/i

# Patterns
/(sales|services)\d{1,2}/i

/aaa/i

# Sample: ＜Subject Line＞
/^\.?[a-z]{5,15}.?\/$/i

# Emojis
# ------------------------------------------------------------------------------
/🦊/i

